SELECT BUYER_CD , CONT_NUM , CONT_CNT FROM STOCECCT WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD || CONT_NUM || CONT_CNT IN
#{value}
AND DEL_FLAG = '0'

mapper.update:

UPDATE STOCECCT SET
	   IF_YN = '1'
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}

mapper.select:
SELECT K.GATE_CD ,K.UUID ,K.UUID_SQ ,K.FILE_NM ,K.FILE_PATH ,K.FILE_SIZE ,K.FILE_EXTENSION ,K.REAL_FILE_NM||'.'||K.FILE_EXTENSION REAL_FILE_NM ,K.BIZ_TYPE ,K.REG_DATE ,K.REG_USER_ID ,K.MOD_DATE ,K.MOD_USER_ID ,K.FILE_SQ ,K.DEL_FLAG ,K.ENC_FLAG ,A.BUYER_CD ,A.CONT_NUM ,A.CONT_CNT ,A.PR_BUYER_CD ,A.PR_DEPT_CD FROM STOCECPC A JOIN STOCATCH K ON A.GATE_CD = K.GATE_CD AND A.PDF_ATT_FILE_NUM = K.UUID AND K.DEL_FLAG = '0' WHERE A.GATE_CD = #{ses.gateCd} AND A.BUYER_CD = #{BUYER_CD} AND A.CONT_NUM = #{CONT_NUM} AND A.CONT_CNT = #{CONT_CNT}
UNION ALL/*===============================================================================================*/
SELECT K.GATE_CD ,K.UUID ,K.UUID_SQ ,K.FILE_NM ,K.FILE_PATH ,K.FILE_SIZE ,K.FILE_EXTENSION ,K.REAL_FILE_NM||'.'||K.FILE_EXTENSION REAL_FILE_NM ,K.BIZ_TYPE ,K.REG_DATE ,K.REG_USER_ID ,K.MOD_DATE ,K.MOD_USER_ID ,K.FILE_SQ ,K.DEL_FLAG ,K.ENC_FLAG ,A.BUYER_CD ,A.CONT_NUM ,A.CONT_CNT ,A.PR_BUYER_CD ,A.PR_DEPT_CD FROM STOCECPC A JOIN STOCATCH K ON A.GATE_CD = K.GATE_CD AND A.ATT_FILE_NUM = K.UUID AND K.DEL_FLAG = '0' WHERE A.GATE_CD = '100' AND A.BUYER_CD = #{BUYER_CD} AND A.CONT_NUM = #{CONT_NUM} AND A.CONT_CNT = #{CONT_CNT} AND A.PAY_CNT = '0' AND A.GUAR_TYPE = 'CONT'
UNION ALL/*===============================================================================================*/
SELECT K.GATE_CD ,K.UUID ,K.UUID_SQ ,K.FILE_NM ,K.FILE_PATH ,K.FILE_SIZE ,K.FILE_EXTENSION ,K.REAL_FILE_NM ,K.BIZ_TYPE ,K.REG_DATE ,K.REG_USER_ID ,K.MOD_DATE ,K.MOD_USER_ID ,K.FILE_SQ ,K.DEL_FLAG ,K.ENC_FLAG ,A.BUYER_CD ,A.CONT_NUM ,A.CONT_CNT ,'' PR_BUYER_CD ,'' PR_DEPT_CD FROM STOCECCT A JOIN STOCATCH K ON A.GATE_CD = K.GATE_CD AND A.ATT_FILE_NUM = K.UUID AND K.DEL_FLAG = '0' WHERE A.GATE_CD = #{ses.gateCd} AND A.BUYER_CD = #{BUYER_CD} AND A.CONT_NUM = #{CONT_NUM} AND A.CONT_CNT = #{CONT_CNT}
UNION ALL/*===============================================================================================*/
SELECT K.GATE_CD ,K.UUID ,K.UUID_SQ ,K.FILE_NM ,K.FILE_PATH ,K.FILE_SIZE ,K.FILE_EXTENSION ,K.REAL_FILE_NM ,K.BIZ_TYPE ,K.REG_DATE ,K.REG_USER_ID ,K.MOD_DATE ,K.MOD_USER_ID ,K.FILE_SQ ,K.DEL_FLAG ,K.ENC_FLAG ,A.BUYER_CD ,A.CONT_NUM ,A.CONT_CNT ,'' PR_BUYER_CD ,'' PR_DEPT_CD FROM STOCECCT A JOIN STOCATCH K ON A.GATE_CD = K.GATE_CD AND A.VENDOR_ATT_FILE_NUM = K.UUID AND K.DEL_FLAG = '0' WHERE A.GATE_CD = #{ses.gateCd} AND A.BUYER_CD = #{BUYER_CD} AND A.CONT_NUM = #{CONT_NUM} AND A.CONT_CNT = #{CONT_CNT}
